This is useful for dashboards, filters, and statistics.

5. Group items

const users = [
{ name: "Ali", role: "admin" },
{ name: "Sara", role: "user" },
{ name: "Omar", role: "admin" },
];
const usersByRole = users.reduce((groups, user) => {
if (!groups[user.role]) {
groups[user.role] = [];
}
groups[user.role].push(user);
return groups;
}, {});
console.log(usersByRole);

