6. Create an object from an array

const users = [
{ id: 1, name: "Ali" },
{ id: 2, name: "Sara" },
];
const usersById = users.reduce((result, user) => {
result[user.id] = user;
return result;
}, {});
console.log(usersById);

Enter fullscreen mode

Exit fullscreen mode

Result:

{
1: { id: 1, name: "Ali" },
2: { id: 2, name: "Sara" }
}

Enter fullscreen mode

Exit fullscreen mode

Now you can quickly find a user:

console.log(usersById[2].name); // Sara

